targets.query:
// CPU 사용률 계산
// idle mode derivative = 초당 idle 소비 비율 (코어당 0~1)
// (1 - idle_rate) * 100 = CPU 사용률(%)
// group() → mean() 으로 전체 코어 평균 산출
from(bucket: v.bucket)
  |> range(start: -5m)
  |> filter(fn: (r) => r._measurement == "eve_ng_prometheus")
  |> filter(fn: (r) => r._field == "node_cpu_seconds_total")
  |> filter(fn: (r) => r.mode == "idle")
  |> derivative(unit: 1s, nonNegative: true)
  |> map(fn: (r) => ({ r with _value: (1.0 - r._value) * 100.0 }))
  |> group()
  |> mean()

// 메모리 사용률 계산
// pivot 으로 MemTotal/MemAvailable 을 같은 행에 배치 후 계산
// map 에서 _time/_value 만 명시 반환 → extra 컬럼 제거 → 단일 series
from(bucket: v.bucket)
  |> range(start: -5m)
  |> filter(fn: (r) => r._measurement == "eve_ng_prometheus")
  |> filter(fn: (r) => r._field == "node_memory_MemTotal_bytes" or r._field == "node_memory_MemAvailable_bytes")
  |> last()
  |> pivot(rowKey: ["_time"], columnKey: ["_field"], valueColumn: "_value")
  |> map(fn: (r) => ({
       _time: r._time,
       _value: (r.node_memory_MemTotal_bytes - r.node_memory_MemAvailable_bytes) / r.node_memory_MemTotal_bytes * 100.0
     }))

// 루트 파일시스템 사용률
// mountpoint='/' 태그로 루트 파티션만 필터링
// map 에서 _time/_value 만 명시 반환 → extra 컬럼 제거 → 단일 series
from(bucket: v.bucket)
  |> range(start: -5m)
  |> filter(fn: (r) => r._measurement == "eve_ng_prometheus")
  |> filter(fn: (r) => r._field == "node_filesystem_size_bytes" or r._field == "node_filesystem_avail_bytes")
  |> filter(fn: (r) => r.mountpoint == "/")
  |> last()
  |> pivot(rowKey: ["_time", "mountpoint"], columnKey: ["_field"], valueColumn: "_value")
  |> map(fn: (r) => ({
       _time: r._time,
       _value: (r.node_filesystem_size_bytes - r.node_filesystem_avail_bytes) / r.node_filesystem_size_bytes * 100.0
     }))

// 업타임 계산
// 현재 Unix 타임스탬프(nanoseconds) / 1e9 - boot_time(초) = 업타임(초)
from(bucket: v.bucket)
  |> range(start: -5m)
  |> filter(fn: (r) => r._measurement == "eve_ng_prometheus")
  |> filter(fn: (r) => r._field == "node_boot_time_seconds")
  |> last()
  |> map(fn: (r) => ({
       r with
       _value: float(v: uint(v: now())) / 1000000000.0 - r._value
     }))

// 메모리 used 시계열
// pivot 으로 MemTotal/MemAvailable 을 같은 행에 배치 후 used 계산
// record 를 명시적으로 구성하여 _field: "used" 라벨 지정
used = from(bucket: v.bucket)
  |> range(start: v.timeRangeStart, stop: v.timeRangeStop)
  |> filter(fn: (r) => r._measurement == "eve_ng_prometheus")
  |> filter(fn: (r) => r._field == "node_memory_MemTotal_bytes" or r._field == "node_memory_MemAvailable_bytes")
  |> aggregateWindow(every: v.windowPeriod, fn: last, createEmpty: false)
  |> pivot(rowKey: ["_time"], columnKey: ["_field"], valueColumn: "_value")
  |> map(fn: (r) => ({
       _time: r._time,
       _field: "used",
       _value: r.node_memory_MemTotal_bytes - r.node_memory_MemAvailable_bytes
     }))

// 메모리 cached 시계열
cached = from(bucket: v.bucket)
  |> range(start: v.timeRangeStart, stop: v.timeRangeStop)
  |> filter(fn: (r) => r._measurement == "eve_ng_prometheus")
  |> filter(fn: (r) => r._field == "node_memory_Cached_bytes")
  |> aggregateWindow(every: v.windowPeriod, fn: last, createEmpty: false)
  |> map(fn: (r) => ({
       _time: r._time,
       _field: "cached",
       _value: r._value
     }))

// group(columns: [_field]) 필수
// 누락 시 Grafana 가 series 명을 _field 값(used/cached) 대신 컬럼명(_value)으로 표시
union(tables: [used, cached])
  |> group(columns: ["_field"])

// 마운트 포인트별 사용률
// fstype=ext4: tmpfs/devtmpfs 등 가상 파일시스템 제외
// mountpoint !~ /\/tmp\/: EVE-NG 가 VM 실행 시 동적 생성하는
//   /opt/unetlab/tmp/0/<uuid>/... 경로 제외
// map 에서 _time/_field/_value 만 반환
//   _field = mountpoint → bar gauge 라벨
from(bucket: v.bucket)
  |> range(start: -5m)
  |> filter(fn: (r) => r._measurement == "eve_ng_prometheus")
  |> filter(fn: (r) => r._field == "node_filesystem_size_bytes" or r._field == "node_filesystem_avail_bytes")
  |> filter(fn: (r) => r.fstype == "ext4")
  |> filter(fn: (r) => r.mountpoint !~ /\/tmp\//)
  |> last()
  |> pivot(rowKey: ["_time", "mountpoint", "device"], columnKey: ["_field"], valueColumn: "_value")
  |> map(fn: (r) => ({
       _time: r._time,
       _field: r.mountpoint,
       _value: (r.node_filesystem_size_bytes - r.node_filesystem_avail_bytes) / r.node_filesystem_size_bytes * 100.0
     }))
